import { useState } from "react";
import { motion } from "framer-motion";
import { Video, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import YouTubeExpandedContent, { YOUTUBE_EXPANDED_FAQS } from "@/components/YouTubeExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 0 });
}


const FAQS = [
  { q: "How much does it cost to produce a YouTube video?", a: "Entry-level self-produced videos cost $50-$200 (mic, lighting, basic editing time). Mid-level production with professional editing runs $200-$800 per video. High-production channels with hired editors, B-roll, and graphics spend $500-$3,000+ per video." },
  { q: "Should I hire a video editor or edit myself?", a: "If your time is worth more than a freelance editor's rate ($20-$75/hour), hire an editor. Most creators earning over $3,000/month from YouTube benefit from outsourcing editing, freeing time for scripting, filming, and audience growth activities." },
  { q: "How do I amortize camera and equipment costs per video?", a: "Divide total equipment cost by estimated number of videos you'll produce with it. A $2,000 camera producing 100 videos adds $20/video in cost. Factor in a 3-5 year lifespan for most camera equipment." },
  { q: "What is a good profit margin for a YouTube video?", a: "For pure AdSense revenue, profit margins depend heavily on channel size. Most monetized channels see 40-70% profit margins once equipment is paid off. Sponsorships dramatically improve margins since the sponsorship fee often exceeds production costs entirely." },
  { q: "How do I calculate YouTube video ROI?", a: "Video ROI = (Total Revenue - Production Cost)  x  Production Cost  x  100. Include all revenue streams: AdSense, sponsorships, affiliate commissions, and course/product sales attributed to the video. A single high-performing video can deliver ROI over multiple years." },
  { q: "What are typical freelance video editor rates?", a: "Entry-level editors (Fiverr): $15-$25/hour. Mid-level editors: $30-$60/hour. Senior editors with motion graphics: $60-$120/hour. YouTube-specialized editors who understand retention optimization are worth paying a premium for." },
];

const EXPANDED_FAQS = YOUTUBE_EXPANDED_FAQS.productionCost;

export default function VideoProductionCostCalculator() {
  useCurrencyVersion();
  const [equipmentMonthly, setEquipmentMonthly] = useState(150);
  const [editingHours, setEditingHours] = useState(4);
  const [editingRate, setEditingRate] = useState(35);
  const [miscPerVideo, setMiscPerVideo] = useState(20);
  const [videosPerMonth, setVideosPerMonth] = useState(4);
  const [expectedRevPerVideo, setExpectedRevPerVideo] = useState(80);

  const editingCost = editingHours * editingRate;
  const equipmentPerVideo = videosPerMonth > 0 ? equipmentMonthly / videosPerMonth : 0;
  const costPerVideo = editingCost + equipmentPerVideo + miscPerVideo;
  const monthlyProduction = costPerVideo * videosPerMonth;
  const profitPerVideo = expectedRevPerVideo - costPerVideo;
  const roiPct = costPerVideo > 0 ? (profitPerVideo / costPerVideo) * 100 : 0;

  return (
    <>
      <SEOHead
        title="Free Video Production Cost Calculator Online 2025 - Calculate Cost Per Video Instantly | CalcHive"
        description="Free video production cost calculator online. Calculate your exact cost per video including editing time, equipment amortization and all production expenses. 100% free for creators and agencies, no signup."
        canonical="/video-production-cost-calculator"
        keywords="free video production cost calculator, video cost calculator free online, calculate video production cost free, cost per video calculator free, video making cost estimator free, youtube video production cost calculator free"
        category="YouTube"
        schemaType="WebApplication"
        schemaApplicationCategory="CalculatorApplication"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-red-600 dark:text-red-400 bg-red-50 dark:bg-red-950/50 px-3 py-1 rounded-full mb-4">
            <Video className="w-3.5 h-3.5" /> YouTube
          </span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Video Production Cost Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free video production cost calculator to calculate video production cost free from editing time, equipment amortization, and production expenses. It works as a video cost calculator free online, cost per video calculator free, video making cost estimator free, and youtube video production cost calculator free for creators and agencies.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="equipment-monthly" label="Monthly Equipment Cost (amortized)" value={equipmentMonthly} min={0} max={2000} step={10} onChange={setEquipmentMonthly} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}/month`} testId="input-equipment" helpText="Camera, mic, lights - divide purchase price by months of use" />
            <SliderInput id="editing-hours" label="Editing Hours per Video" value={editingHours} min={0.5} max={40} step={0.5} onChange={setEditingHours} format={v => `${v} hours`} testId="input-editing-hours" />
            <SliderInput id="editing-rate" label="Editing Hourly Rate" value={editingRate} min={5} max={150} step={1} onChange={setEditingRate} format={v => `${formatCurrencyValue(v, { maximumFractionDigits: 0 })}/hr`} testId="input-editing-rate" helpText="Your time value or freelancer rate" />
            <SliderInput id="misc-cost" label="Misc. Costs per Video" value={miscPerVideo} min={0} max={500} step={5} onChange={setMiscPerVideo} format={v => formatCurrencyValue(v, { maximumFractionDigits: 0 })} testId="input-misc" helpText="Props, locations, music licenses, thumbnails" />
            <SliderInput id="videos-per-month" label="Videos per Month" value={videosPerMonth} min={1} max={30} step={1} onChange={setVideosPerMonth} format={v => `${v} video${v === 1 ? "" : "s"}/month`} testId="input-videos-per-month" />
            <SliderInput id="expected-rev" label="Expected Revenue per Video" value={expectedRevPerVideo} min={0} max={5000} step={5} onChange={setExpectedRevPerVideo} format={v => formatCurrencyValue(v, { maximumFractionDigits: 0 })} testId="input-expected-rev" helpText="AdSense + sponsorship + affiliate per video avg" />
          </div>
          <motion.div key={`${equipmentMonthly}-${editingHours}-${editingRate}-${miscPerVideo}-${videosPerMonth}-${expectedRevPerVideo}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${roiPct >= 0 ? "from-red-500 to-red-700" : "from-rose-600 to-rose-800"} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Cost per Video</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-cost-per-video">{fmt(costPerVideo)}</p>
              <p className="text-white/70 text-sm mt-1">Profit: {fmt(profitPerVideo)} - ROI: {roiPct.toFixed(0)}%</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[
                { label: "Editing Cost", value: fmt(editingCost) },
                { label: "Equipment per Video", value: fmt(equipmentPerVideo) },
                { label: "Monthly Production Cost", value: fmt(monthlyProduction) },
                { label: "Profit per Video", value: fmt(profitPerVideo), highlight: profitPerVideo >= 0 },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Video Production Cost for Free</h2>
          <p className="text-muted-foreground leading-relaxed">True video production cost includes three components: editing time (hours  x  hourly rate), equipment cost amortized per video (monthly equipment expense divided by videos produced), and miscellaneous expenses (props, music, thumbnail design). Comparing total cost against expected revenue per video gives you profit per video and ROI - the key metrics for making informed creator economy decisions about outsourcing, equipment investment, and content strategy.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Editing Cost = Hours  x  Hourly Rate</p>
            <p>Equipment/Video = Monthly Equipment  x  Videos/Month</p>
            <p>Cost/Video = Editing + Equipment/Video + Misc</p>
            <p>ROI = (Revenue - Cost)  x  Cost  x  100</p>
          </div>
          <h2 className="text-2xl font-bold text-foreground">What is Included in the Cost of Making a Video</h2>
          <p className="text-muted-foreground leading-relaxed">Include editing labor, equipment, software, music, props, locations, thumbnails, contractors, and any recurring production expense tied to each video.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Reduce Your Video Production Costs</h2>
          <p className="text-muted-foreground leading-relaxed">Batch filming, reusable templates, better pre-production, and clear editing briefs can reduce cost per video without lowering quality.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Video Cost Estimator for Creators and Agencies</h2>
          <p className="text-muted-foreground leading-relaxed">Use the estimate to price client work, compare editing options, or decide whether a video idea can produce a positive ROI.</p>
        </section>
        <YouTubeExpandedContent kind="productionCost" />

        <section className="mb-8">
          <h2 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/video-production-cost-calculator" headingLevel="h3" />
      </main>
    </>
  );
}




